#!/usr/bin/env tsx
/**
 * Check that @generated files haven't been manually edited
 * Verifies timestamps and warns if files are out of sync
 */
import { readFileSync, existsSync, statSync } from 'node:fs';
import { join, relative } from 'node:path';
import { globSync } from 'glob';

interface GeneratedFileInfo {
  path: string;
  version: string;
  generatedFrom: string;
  lastGenerated: string;
  fileModified: string;
  isModified: boolean;
}

const GENERATED_MARKER = '@generated by flusk CLI';

function extractGeneratedInfo(content: string, filePath: string): GeneratedFileInfo | null {
  const lines = content.split('\n');
  const markerLine = lines.find((line) => line.includes(GENERATED_MARKER));

  if (!markerLine) {
    return null;
  }

  // Extract metadata from header comments
  const versionMatch = content.match(/@generated by flusk CLI v([\d.]+)/);
  const sourceMatch = content.match(/Generated from: (.+)/);
  const timestampMatch = content.match(/Last generated: (.+)/);

  const stats = statSync(filePath);
  const fileModified = stats.mtime.toISOString();
  const lastGenerated = timestampMatch?.[1] || '';

  // Check if file was modified after generation
  const isModified = lastGenerated
    ? new Date(fileModified) > new Date(lastGenerated)
    : false;

  return {
    path: filePath,
    version: versionMatch?.[1] || 'unknown',
    generatedFrom: sourceMatch?.[1] || 'unknown',
    lastGenerated,
    fileModified,
    isModified,
  };
}

function main() {
  console.log('🔍 Checking Generated Files\n');

  // Find all TypeScript files in packages
  const files = globSync('packages/**/src/**/*.{ts,js}', {
    ignore: ['**/node_modules/**', '**/dist/**'],
    absolute: true,
  });

  const generatedFiles: GeneratedFileInfo[] = [];
  const modifiedFiles: GeneratedFileInfo[] = [];

  for (const file of files) {
    try {
      const content = readFileSync(file, 'utf-8');
      const info = extractGeneratedInfo(content, file);

      if (info) {
        generatedFiles.push(info);
        if (info.isModified) {
          modifiedFiles.push(info);
        }
      }
    } catch (error) {
      // Skip files that can't be read
      continue;
    }
  }

  console.log(`📊 Found ${generatedFiles.length} generated files\n`);

  // Report modified files
  if (modifiedFiles.length > 0) {
    console.warn('⚠️  Warning: The following generated files appear to have been manually edited:\n');

    for (const file of modifiedFiles) {
      const relPath = relative(process.cwd(), file.path);
      console.warn(`  ❌ ${relPath}`);
      console.warn(`     Generated: ${file.lastGenerated}`);
      console.warn(`     Modified:  ${file.fileModified}`);
      console.warn(`     Source:    ${file.generatedFrom}\n`);
    }

    console.warn('\n💡 To fix: Run `pnpm generate` to regenerate files from entities\n');
    console.warn('⚠️  Manual edits will be LOST when files are regenerated!\n');
    process.exit(1);
  }

  // Report out-of-sync files (entity newer than generated file)
  const outOfSync: Array<{ file: string; entity: string }> = [];

  for (const file of generatedFiles) {
    const entityPath = join(process.cwd(), file.generatedFrom);

    if (existsSync(entityPath)) {
      const entityStats = statSync(entityPath);
      const fileStats = statSync(file.path);

      if (entityStats.mtime > fileStats.mtime) {
        outOfSync.push({
          file: relative(process.cwd(), file.path),
          entity: relative(process.cwd(), entityPath),
        });
      }
    }
  }

  if (outOfSync.length > 0) {
    console.warn('⚠️  Warning: The following files are out of sync with their entities:\n');

    for (const { file, entity } of outOfSync) {
      console.warn(`  🔄 ${file}`);
      console.warn(`     Entity: ${entity}\n`);
    }

    console.warn('\n💡 To fix: Run `pnpm generate` to regenerate files\n');
    process.exit(1);
  }

  console.log('✅ All generated files are in sync!\n');
}

main();
